export function initialize(element, dotNetRef, timeoutMs) {
    const state = { timerId: null, isIdle: false };

    function resetTimer() {
        clearTimeout(state.timerId);
        if (state.isIdle) {
            state.isIdle = false;
            dotNetRef.invokeMethodAsync("OnUserActive");
        }
        state.timerId = setTimeout(() => {
            state.isIdle = true;
            dotNetRef.invokeMethodAsync("OnUserIdle");
        }, timeoutMs);
    }

    const events = ["mousemove", "keydown", "click", "scroll", "touchstart"];
    events.forEach(evt => element.addEventListener(evt, resetTimer, { passive: true }));

    // Start the initial timer
    state.timerId = setTimeout(() => {
        state.isIdle = true;
        dotNetRef.invokeMethodAsync("OnUserIdle");
    }, timeoutMs);

    // Return a handle so we can dispose later
    element.__activityState = state;
    element.__activityEvents = events;
    element.__activityHandler = resetTimer;
}

export function dispose(element) {
    if (!element) return;
    const state = element.__activityState;
    if (state) {
        clearTimeout(state.timerId);
    }
    const events = element.__activityEvents;
    const handler = element.__activityHandler;
    if (events && handler) {
        events.forEach(evt => element.removeEventListener(evt, handler));
    }
    delete element.__activityState;
    delete element.__activityEvents;
    delete element.__activityHandler;
}

